ALGORITHM FrameAllocation
INPUT: totalFrames, processList (each with size)
OUTPUT: frame allocation for each process

// EQUAL ALLOCATION
FUNCTION EqualAllocation(totalFrames, numProcesses)
  framesPerProcess = totalFrames / numProcesses
  RETURN framesPerProcess

// PROPORTIONAL ALLOCATION  
FUNCTION ProportionalAllocation(totalFrames, processList)
  totalSize = SUM(process.size) FOR ALL processes
  FOR EACH p IN processList
    allocation[p.id] = (p.size / totalSize) * totalFrames
  RETURN allocation

// Example usage:
// totalFrames = 100, processes = [50KB, 150KB]
// Equal: 50 frames each
// Proportional: P1=(50/200)*100=25, P2=(150/200)*100=75

ALGORITHM WorkingSetCalculator
INPUT: referenceString, windowSize Delta
OUTPUT: working set size and frame requirements

FUNCTION CalculateWorkingSet(referenceString, delta)
  // referenceString: sequence of page references
  // delta: time window size (number of references)

  workingSets = EMPTY LIST

  FOR i FROM 0 TO referenceString.length - delta:
    // Get pages in current window
    currentWindow = referenceString[i TO i+delta-1]

    // Find unique pages in window (the working set)
    ws = UNIQUE_PAGES(currentWindow)
    workingSets.add(ws)

    // Track maximum working set seen
    maxWSSize = MAX(maxWSSize, ws.size)

  RETURN maxWSSize  // Frames needed for this process

// Example:
// Reference: 1,2,3,1,2,3,4,2,1,4, delta=4
// Window 1: {1,2,3} = 3 frames
// Window 2: {1,2,3} = 3 frames  
// Window 3: {3,4,2} = 3 frames
// Maximum: 3 frames needed
